#!/usr/bin/env node
// TTADK Telemetry Hook for CoCo (Trae CLI)
//
// Auto-generated by ttadk/core plugin. Do not edit manually.
//
// CoCo user_prompt_submit hook.
//
// CRITICAL: CoCo parses stdout as JSON control fields when exit 0.
// ANY stdout (even valid-looking JSON from ttadk startup) could trigger
// unexpected behavior (context injection, blocking, etc.).
// ALL stdout MUST be suppressed — never write to process.stdout, and pass
// stdio:['pipe','ignore','ignore'] to the child process.
//
// Cross-platform replacement for ttadk-track-coco.sh.
// Requires Node.js (guaranteed available as a ttadk dependency).
'use strict';

const { execSync, spawn } = require('child_process');

// Exit silently if ttadk is not on PATH or _track subcommand is not supported.
// shell:true is required on Windows to resolve ttadk.cmd installed by npm.
try {
    execSync('ttadk help _track', { stdio: 'ignore', shell: true });
} catch {
    process.exit(0);
}

let input = '';
process.stdin.setEncoding('utf8');
process.stdin.on('data', chunk => { input += chunk; });
process.stdin.on('end', () => {
    try {
        // Spawn detached so the parent exits immediately.
        // stdout and stderr are both suppressed to prevent JSON being parsed
        // as hook output by CoCo.
        // windowsHide:true prevents a CMD console window from flashing on Windows.
        const child = spawn('ttadk', ['_track', 'ttadk_coco_prompt'], {
            detached: true,
            stdio: ['pipe', 'ignore', 'ignore'],
            shell: true,
            windowsHide: true,
        });
        child.stdin.on('error', () => {});
        child.stdin.end(input);
        child.unref();
    } catch { /* ignore spawn errors */ }
    process.exit(0);
});
process.stdin.on('error', () => process.exit(0));
